async function togglePipMode() {
    const btn = document.getElementById('btn-set-pip');
    if (!btn) return;

    if (!btn.classList.contains('active')) {
        // Accendiamo il bottone e apriamo (attendendo il caricamento)
        btn.classList.add('active');
        try {
            await openPipCalibrator(window.pipConfig);
        } catch (e) {
            btn.classList.remove('active'); // Spegni se fallisce l'apertura
            console.error("Errore apertura calibratore:", e);
        }
    } else {
        // Chiudiamo e spegniamo il bottone
        closePipCalibrator(); 
        // Nota: closePipCalibrator dovrebbe contenere: 
        // btn.classList.remove('active');
    }
}


